import{_ as i,c as n,o as g,a6 as A}from"./chunks/framework.Bw_bo0GO.js";const _=JSON.parse('{"title":"离散数学","description":"","frontmatter":{},"headers":[],"relativePath":"science/discrete-math.md","filePath":"science/discrete-math.md","lastUpdated":1709722080000}'),c={name:"science/discrete-math.md"},s=A('<h1 id="离散数学" tabindex="-1">离散数学 <a class="header-anchor" href="#离散数学" aria-label="Permalink to &quot;离散数学&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">要学到的</p><p>离散数学基础: 集合、偏序集、良序、数学归纳法、级数、递归、递推</p></div><h2 id="概念定义" tabindex="-1">概念定义 <a class="header-anchor" href="#概念定义" aria-label="Permalink to &quot;概念定义&quot;">​</a></h2><p><strong>集合基数</strong>: 集合 A 中元素的数目称为集合A的基数(base number), 记为|A|</p><ul><li>如|A|是有限的, 则称A为<strong>有限集</strong></li><li>如|A|是无限的, 则称A为<strong>无限集</strong></li></ul><p><strong>m元子集</strong>: 如果一个集合A中含有n个元素, 则称集合A为<strong>n元集</strong>, 称A的含有m个($0\\le m\\le n$)元素的子集为<strong>A的m元子集</strong>.</p><p><strong>子集总数</strong>: 一般来说, 对于n元集A, 它的m($0\\le m\\le n$)元子集$C_n^m$个, 所以不同的子集总数有:<br> $C_n^0+C_n^1+C_n^2+...+C_n^n=2^n$ 所以, n元集共有$2^n$个子集</p><p><strong>幂集</strong>: 设A为任意集合, 把A的<strong>所有不同子集</strong>为元素构成的集合叫做A的<strong>幂集</strong>(power set), 记为 <strong>P(A)</strong> 或$2^A$<br> 符号化表示:<br> $P(A) = { x| 一切 \\subseteq A}$<br> 该集合又称为<strong>集族</strong>(family of set)<br> 对集族的研究在数学方面、知识库和表处理语言及人工智能等方面都有十分重要的意义<br> 显然, 若集合A有n个元素, 则集合A共有$2^{|A|}$个子集, 即<br> $|P(A)| = 2^{|A|}$</p><p><strong>集合的运算</strong>:<br> 设A、B为任意集合, U为全集</p><ul><li><strong>并集</strong> $A \\bigcup B = { X | X \\in A 或 X \\in B}$</li><li><strong>交集</strong> $A \\bigcap B = { X | X \\in A 且 X \\in B}$</li><li><strong>差集</strong> $A - B = { X | X \\in A 且 X \\notin B}$</li><li><strong>补集</strong> $\\bar{A} = U - A = { X | X \\in U 且 X \\notin A} \\space\\space({A}&#39;,\\space \\sim A, \\space A^C)$</li><li><strong>对称差集</strong> $A \\oplus B = { X| ((X \\in A) 且 (X \\notin B)) 或((X \\in B)且(X \\notin A)) }$</li></ul><p>推广:<br> $$\\bigcup_{i=1}^{n} A_{i} = \\bigcup_{i\\in{1,2,...,n}}^{n} A_{i} = A_1\\bigcup A_2\\bigcup A_3\\bigcup ... \\bigcup A_n = { X | (X \\in A_1) 或 (X \\in A_2) 或 ... 或 (X \\in A_n) } $$ $$\\bigcap_{i=1}^{n} A_{i} = \\bigcap_{i\\in{1,2,...,n}}^{n} A_{i} = A_1\\bigcap A_2\\bigcap A_3\\bigcap ... \\bigcap A_n = { X | (X \\in A_1) 且 (X \\in A_2) 且 ... 且 (X \\in A_n) } $$ 当n无限增大时, 可以记为 $$\\bigcup_{i=1}^{\\infty } A_{i} = \\bigcup_{i\\in Z^+ } A_{i} = A_1\\bigcup A_2\\bigcup A_3\\bigcup ... $$ $$\\bigcap_{i=1}^{\\infty } A_{i} = \\bigcap_{i\\in Z^+ } A_{i} = A_1\\bigcap A_2\\bigcap A_3\\bigcap ... $$</p><p>差和补运算的几个性质</p><ul><li>$A - A = \\Phi$</li><li>$A - B = A - (A\\bigcap B)$</li><li>$A \\bigcup (B-A)=A\\bigcup B$</li><li>$A-B=A\\bigcap \\bar {B}$</li><li>$(A-B)-C=A-(B\\bigcup C)$</li></ul><p>定理<br> 设A、B、C为任意集合, U为全集, $\\Phi$为空集</p><ul><li><strong>幂等律</strong> $A \\bigcup A=A; \\space\\space A\\bigcap A=A$</li><li><strong>恒等律</strong> $A \\bigcup \\Phi =A; \\space\\space A\\bigcap U=A$</li><li><strong>零律</strong> $A \\bigcup U =U; \\space\\space A\\bigcap \\Phi=\\Phi$</li><li><strong>否定律</strong> $\\bar{\\bar{A}}=A$</li><li><strong>矛盾律</strong> $A\\bigcap \\bar{A}=\\Phi$</li><li><strong>排中律</strong> $A\\bigcup \\bar{A}=U$</li><li><strong>交换律</strong> $A\\bigcup B=B\\bigcup A; \\space\\space A\\bigcap B=B\\bigcap A$</li><li><strong>吸收率</strong> $A\\bigcap(A\\bigcup B)=A;\\space\\space A\\bigcup(A\\bigcap B)=A$</li><li><strong>DeMorgAn律</strong> $\\overline{A\\bigcup{B}}=\\bar{A}\\bigcap\\bar{B};\\space\\space\\overline{A\\bigcap{B}}=\\bar{A}\\bigcup\\bar{B}$</li><li><strong>结合律</strong> $A\\bigcup(B\\bigcup{C})=(A\\bigcup{B})\\bigcup{C};\\space\\space A\\bigcap(B\\bigcap{C})=(A\\bigcap{B})\\bigcap{C}$</li><li><strong>分配律</strong> $A\\bigcap(B\\bigcup{C})=(A\\bigcap{B})\\bigcup(A\\bigcap{C});\\space\\space A\\bigcup(B\\bigcap{C})=(A\\bigcup{B})\\bigcap(A\\bigcup{C})$</li></ul>',15),p=[s];function t(a,r,o,b,e,l){return g(),n("div",null,p)}const u=i(c,[["render",t]]);export{_ as __pageData,u as default};
